export class StubEmbedder{dimensions;constructor(e=64){this.dimensions=e}async embed(e){return this.computeEmbedding(e)}async embedBatch(e){return e.map(t=>this.computeEmbedding(t))}computeEmbedding(e){const t=new Array(this.dimensions).fill(0);for(let s=0;s<e.length;s++){const o=e.charCodeAt(s)%this.dimensions;t[o]+=1}const n=Math.sqrt(t.reduce((s,i)=>s+i*i,0));if(n>0)for(let s=0;s<t.length;s++)t[s]=t[s]/n;return t}}export class OpenAIEmbedder{dimensions;apiKey;baseUrl;model;constructor(e){this.apiKey=e.apiKey??process.env.OPENAI_API_KEY??"",this.baseUrl=e.baseUrl??"https://api.openai.com/v1",this.model=e.model,this.dimensions=e.dimensions}async embed(e){const t=await this.embedBatch([e]);if(t.length===0)throw new Error("Embedding API returned empty results");return t[0]}async embedBatch(e){const t=await fetch(`${this.baseUrl}/embeddings`,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${this.apiKey}`},body:JSON.stringify({model:this.model,input:e,dimensions:this.dimensions}),signal:AbortSignal.timeout(6e4)});if(!t.ok)throw new Error(`OpenAI embeddings API error: ${t.status} ${t.statusText}`);const n=await t.json();if(!n.data||!Array.isArray(n.data))throw new Error(`Unexpected embedding response: ${JSON.stringify(n).slice(0,200)}`);return n.data.map(s=>s.embedding)}}export function createEmbedder(r){switch(r.type){case"stub":return new StubEmbedder(r.dimensions);case"openai":return new OpenAIEmbedder(r);default:throw new Error(`Unknown embedder type: ${r.type}`)}}
